import{_ as i,o as e,c as l,ak as s}from"./chunks/framework.24mNDJkT.js";const b=JSON.parse('{"title":"以太网帧格式与 MAC 地址工作机制笔记","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/物理层和数据链路层/链路层的帧格式.md","filePath":"计算机网络/物理层和数据链路层/链路层的帧格式.md","lastUpdated":1775135228000}'),r={name:"计算机网络/物理层和数据链路层/链路层的帧格式.md"};function n(h,a,t,d,o,c){return e(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="以太网帧格式与-mac-地址工作机制笔记" tabindex="-1">以太网帧格式与 MAC 地址工作机制笔记 <a class="header-anchor" href="#以太网帧格式与-mac-地址工作机制笔记" aria-label="Permalink to “以太网帧格式与 MAC 地址工作机制笔记”">​</a></h1><h2 id="一、数据链路层的封装回顾" tabindex="-1">一、数据链路层的封装回顾 <a class="header-anchor" href="#一、数据链路层的封装回顾" aria-label="Permalink to “一、数据链路层的封装回顾”">​</a></h2><p>当数据从上层传到数据链路层时：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>应用层 → 运输层 → 网络层 → 数据链路层</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 此时数据链路层的<strong>数据载荷</strong>包含：</p><ul><li>应用层数据</li><li>应用层首部</li><li>运输层首部</li><li>网络层首部</li></ul><hr><h2 id="二、数据链路层的核心操作-封装成帧" tabindex="-1">二、数据链路层的核心操作：封装成帧 <a class="header-anchor" href="#二、数据链路层的核心操作-封装成帧" aria-label="Permalink to “二、数据链路层的核心操作：封装成帧”">​</a></h2><p>👉 数据链路层会对数据进行：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>加首部 + 加尾部 → 封装成帧（Frame）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="三、以太网-ii-帧格式-重点" tabindex="-1">三、以太网 II 帧格式（重点） <a class="header-anchor" href="#三、以太网-ii-帧格式-重点" aria-label="Permalink to “三、以太网 II 帧格式（重点）”">​</a></h2><h3 id="帧结构如下" tabindex="-1">帧结构如下： <a class="header-anchor" href="#帧结构如下" aria-label="Permalink to “帧结构如下：”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>| 目标MAC(6B) | 源MAC(6B) | 类型(2B) | 数据载荷(46~1500B) | FCS(4B) |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="四、各字段详解" tabindex="-1">四、各字段详解 <a class="header-anchor" href="#四、各字段详解" aria-label="Permalink to “四、各字段详解”">​</a></h2><h3 id="_1️⃣-目标-mac-地址-6-字节" tabindex="-1">1️⃣ 目标 MAC 地址（6 字节） <a class="header-anchor" href="#_1️⃣-目标-mac-地址-6-字节" aria-label="Permalink to “1️⃣ 目标 MAC 地址（6 字节）”">​</a></h3><ul><li>表示：<strong>发给谁</strong></li><li>接收端用于判断： <ul><li>是否接收该帧</li></ul></li></ul><hr><h3 id="_2️⃣-源-mac-地址-6-字节" tabindex="-1">2️⃣ 源 MAC 地址（6 字节） <a class="header-anchor" href="#_2️⃣-源-mac-地址-6-字节" aria-label="Permalink to “2️⃣ 源 MAC 地址（6 字节）”">​</a></h3><ul><li>表示：<strong>从哪来</strong></li><li>用途： <ul><li>接收方可以回复数据</li></ul></li></ul><hr><h3 id="_3️⃣-类型字段-2-字节" tabindex="-1">3️⃣ 类型字段（2 字节） <a class="header-anchor" href="#_3️⃣-类型字段-2-字节" aria-label="Permalink to “3️⃣ 类型字段（2 字节）”">​</a></h3><p>👉 作用：</p><blockquote><p>标识数据载荷使用的上层协议</p></blockquote><hr><h3 id="常见值" tabindex="-1">常见值： <a class="header-anchor" href="#常见值" aria-label="Permalink to “常见值：”">​</a></h3><ul><li><code>0x0800</code> → IPv4</li><li><code>0x0806</code> → ARP</li><li><code>0x86DD</code> → IPv6</li></ul><hr><h3 id="_4️⃣-数据载荷-payload" tabindex="-1">4️⃣ 数据载荷（Payload） <a class="header-anchor" href="#_4️⃣-数据载荷-payload" aria-label="Permalink to “4️⃣ 数据载荷（Payload）”">​</a></h3><p>👉 内容：</p><ul><li>来自网络层的数据（如 IP 数据包）</li></ul><hr><p>👉 长度限制：</p><ul><li>最小：46 字节</li><li>最大：1500 字节</li></ul><hr><h3 id="❗为什么有最大限制" tabindex="-1">❗为什么有最大限制？ <a class="header-anchor" href="#❗为什么有最大限制" aria-label="Permalink to “❗为什么有最大限制？”">​</a></h3><p>👉 如果超过 1500 字节：</p><ul><li>会在上层（网络层）进行<strong>分片（Fragmentation）</strong></li></ul><hr><h3 id="_5️⃣-fcs-帧校验序列-4-字节" tabindex="-1">5️⃣ FCS（帧校验序列，4 字节） <a class="header-anchor" href="#_5️⃣-fcs-帧校验序列-4-字节" aria-label="Permalink to “5️⃣ FCS（帧校验序列，4 字节）”">​</a></h3><p>👉 作用：</p><blockquote><p>检测数据是否在传输过程中发生错误</p></blockquote><hr><p>👉 原理：</p><ul><li>基于校验算法（如 CRC）</li><li>检测比特是否发生“跳变”</li></ul><hr><p>👉 注意：</p><ul><li>❗抓包中<strong>看不到 FCS</strong></li><li>原因： <ul><li>网卡已完成校验并移除</li></ul></li></ul><hr><h2 id="五、抓包验证-wireshark" tabindex="-1">五、抓包验证（Wireshark） <a class="header-anchor" href="#五、抓包验证-wireshark" aria-label="Permalink to “五、抓包验证（Wireshark）”">​</a></h2><p>在抓包工具中可以看到：</p><h3 id="示例结构" tabindex="-1">示例结构： <a class="header-anchor" href="#示例结构" aria-label="Permalink to “示例结构：”">​</a></h3><ul><li>Ethernet II <ul><li>Destination（目标 MAC）</li><li>Source（源 MAC）</li><li>Type（协议类型）</li></ul></li></ul><hr><h3 id="说明" tabindex="-1">说明： <a class="header-anchor" href="#说明" aria-label="Permalink to “说明：”">​</a></h3><ul><li>左边：解析后的字段</li><li>右边：真实二进制数据（十六进制表示）</li></ul><hr><h2 id="六、接收端如何解析帧-重点" tabindex="-1">六、接收端如何解析帧（重点） <a class="header-anchor" href="#六、接收端如何解析帧-重点" aria-label="Permalink to “六、接收端如何解析帧（重点）”">​</a></h2><p>👉 核心依据：</p><blockquote><p><strong>协议规定的格式</strong></p></blockquote><hr><h3 id="解析步骤" tabindex="-1">解析步骤： <a class="header-anchor" href="#解析步骤" aria-label="Permalink to “解析步骤：”">​</a></h3><ol><li>读取前 6 字节 → 目标 MAC</li><li>读取后 6 字节 → 源 MAC</li><li>读取 2 字节 → 类型</li><li>剩余部分 → 数据载荷</li></ol><hr><p>👉 本质：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>按照“固定结构”切割二进制数据</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="七、mac-地址如何起作用" tabindex="-1">七、MAC 地址如何起作用 <a class="header-anchor" href="#七、mac-地址如何起作用" aria-label="Permalink to “七、MAC 地址如何起作用”">​</a></h2><h3 id="接收端判断逻辑" tabindex="-1">接收端判断逻辑： <a class="header-anchor" href="#接收端判断逻辑" aria-label="Permalink to “接收端判断逻辑：”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>目标MAC == 本机MAC ?</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="情况" tabindex="-1">情况： <a class="header-anchor" href="#情况" aria-label="Permalink to “情况：”">​</a></h3><ul><li>✔ 相同 → 接收</li><li>❌ 不同 → 丢弃</li><li>✔ 广播（FF:FF:FF:FF:FF:FF）→ 全部接收</li></ul><hr><h2 id="八、协议的重要性-核心理解" tabindex="-1">八、协议的重要性（核心理解） <a class="header-anchor" href="#八、协议的重要性-核心理解" aria-label="Permalink to “八、协议的重要性（核心理解）”">​</a></h2><p>👉 没有协议：</p><ul><li>0101 无意义（无法解析）</li></ul><p>👉 有协议：</p><ul><li>可以明确： <ul><li>哪些字节表示什么</li><li>如何拆分数据</li></ul></li></ul><hr><h2 id="九、数据逐层解析过程" tabindex="-1">九、数据逐层解析过程 <a class="header-anchor" href="#九、数据逐层解析过程" aria-label="Permalink to “九、数据逐层解析过程”">​</a></h2><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>链路层解析 → 网络层解析 → 运输层解析 → 应用层解析</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><p>👉 每一层：</p><ul><li>读取自己的首部</li><li>提取信息</li><li>去掉首部</li><li>上交数据</li></ul><hr><h2 id="十、关键细节总结" tabindex="-1">十、关键细节总结 <a class="header-anchor" href="#十、关键细节总结" aria-label="Permalink to “十、关键细节总结”">​</a></h2><h3 id="_1️⃣-帧头长度固定" tabindex="-1">1️⃣ 帧头长度固定 <a class="header-anchor" href="#_1️⃣-帧头长度固定" aria-label="Permalink to “1️⃣ 帧头长度固定”">​</a></h3><ul><li>以太网 II： <ul><li>14 字节</li></ul></li></ul><hr><h3 id="_2️⃣-分隔符不重要" tabindex="-1">2️⃣ 分隔符不重要 <a class="header-anchor" href="#_2️⃣-分隔符不重要" aria-label="Permalink to “2️⃣ 分隔符不重要”">​</a></h3><ul><li>Windows：<code>-</code></li><li>Linux / Wireshark：<code>:</code></li></ul><p>👉 本质都是：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>十六进制表示</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="_3️⃣-数据本质不变" tabindex="-1">3️⃣ 数据本质不变 <a class="header-anchor" href="#_3️⃣-数据本质不变" aria-label="Permalink to “3️⃣ 数据本质不变”">​</a></h3><ul><li>一直都是：</li></ul><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>0101（二进制）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="十一、核心总结" tabindex="-1">十一、核心总结 <a class="header-anchor" href="#十一、核心总结" aria-label="Permalink to “十一、核心总结”">​</a></h2><h3 id="一句话总结帧结构" tabindex="-1">一句话总结帧结构 <a class="header-anchor" href="#一句话总结帧结构" aria-label="Permalink to “一句话总结帧结构”">​</a></h3><blockquote><p><strong>数据链路层通过固定格式（帧）组织数据，并通过 MAC 地址实现局域网内通信</strong></p></blockquote><hr><h3 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to “核心流程”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>封装（加头尾） → 发送 → 接收 → 按协议解析</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="最关键理解" tabindex="-1">最关键理解 <a class="header-anchor" href="#最关键理解" aria-label="Permalink to “最关键理解”">​</a></h3><blockquote><p><strong>协议让“无序的二进制数据”变成“有结构的信息”</strong></p></blockquote><hr><p>如果你继续深入学习，下一步最关键的是：</p><p>👉 <strong>ARP 协议（IP → MAC 的映射）</strong></p><p>这个是把“网络层”和“链路层”真正打通的关键机制。</p>',113)])])}const u=i(r,[["render",n]]);export{b as __pageData,u as default};
